<template><div v-bind="$attrs" class="mg-transfer"><section class="mg-transfer__panel"><header><label><input type="checkbox" :checked="leftAll" :indeterminate.prop="leftIndeterminate" @change="toggleAll('left',$event)">{{ titles[0] }}</label><span>{{ leftChecked.length }}/{{ leftItems.length }}</span></header><input v-if="filterable" class="mg-transfer__filter" :value="leftQuery" :placeholder="filterPlaceholder" @input="leftQuery=($event.target as HTMLInputElement).value"><div class="mg-transfer__list"><label v-for="item in filteredLeft" :key="String(item.key)" class="mg-transfer__item"><input type="checkbox" :checked="leftChecked.includes(item.key)" :disabled="item.disabled" @change="toggleChecked('left',item.key)"><slot name="default" :option="item"><component :is="renderContent(h,item)" v-if="renderContent" /><span v-else>{{ item.label }}</span></slot></label><div v-if="!filteredLeft.length" class="mg-transfer__empty"><slot name="left-empty">暂无数据</slot></div></div><footer v-if="$slots['left-footer']"><slot name="left-footer" /></footer></section><div class="mg-transfer__buttons"><button type="button" :disabled="!rightChecked.length" @click="move('left')">{{ buttonTexts[0] || '‹' }}</button><button type="button" :disabled="!leftChecked.length" @click="move('right')">{{ buttonTexts[1] || '›' }}</button></div><section class="mg-transfer__panel"><header><label><input type="checkbox" :checked="rightAll" :indeterminate.prop="rightIndeterminate" @change="toggleAll('right',$event)">{{ titles[1] }}</label><span>{{ rightChecked.length }}/{{ rightItems.length }}</span></header><input v-if="filterable" class="mg-transfer__filter" :value="rightQuery" :placeholder="filterPlaceholder" @input="rightQuery=($event.target as HTMLInputElement).value"><div class="mg-transfer__list"><label v-for="item in filteredRight" :key="String(item.key)" class="mg-transfer__item"><input type="checkbox" :checked="rightChecked.includes(item.key)" :disabled="item.disabled" @change="toggleChecked('right',item.key)"><slot name="default" :option="item"><component :is="renderContent(h,item)" v-if="renderContent" /><span v-else>{{ item.label }}</span></slot></label><div v-if="!filteredRight.length" class="mg-transfer__empty"><slot name="right-empty">暂无数据</slot></div></div><footer v-if="$slots['right-footer']"><slot name="right-footer" /></footer></section></div></template>
<script setup lang="ts">
import { computed, h, inject, ref, type VNode } from 'vue'; import { formItemContextKey } from '@metagravity_cn/primitives'
export type TransferKey=string|number; export interface TransferData{key:TransferKey;label:string;disabled?:boolean;[key:string]:unknown}; defineOptions({name:'MgTransfer',inheritAttrs:false}); const props=withDefaults(defineProps<{modelValue?:TransferKey[];data?:TransferData[];filterable?:boolean;filterPlaceholder?:string;filterMethod?:(query:string,item:TransferData)=>boolean;titles?:[string,string];buttonTexts?:[string,string];targetOrder?:'original'|'push'|'unshift';renderContent?:(createElement:typeof h,option:TransferData)=>VNode;leftDefaultChecked?:TransferKey[];rightDefaultChecked?:TransferKey[];validateEvent?:boolean}>(),{modelValue:()=>[],data:()=>[],filterPlaceholder:'请输入搜索内容',titles:()=>['列表 1','列表 2'],buttonTexts:()=>['',''],targetOrder:'original',leftDefaultChecked:()=>[],rightDefaultChecked:()=>[],validateEvent:true}); const emit=defineEmits<{'update:modelValue':[value:TransferKey[]];change:[value:TransferKey[],direction:'left'|'right',movedKeys:TransferKey[]];'left-check-change':[value:TransferKey[],moved?:TransferKey[]];'right-check-change':[value:TransferKey[],moved?:TransferKey[]]}>(); const formItem=inject(formItemContextKey,undefined); const leftQuery=ref('');const rightQuery=ref('');const leftChecked=ref([...props.leftDefaultChecked]);const rightChecked=ref([...props.rightDefaultChecked]); const rightItems=computed(()=>props.modelValue.map(key=>props.data.find(item=>Object.is(item.key,key))).filter((item):item is TransferData=>Boolean(item))); const leftItems=computed(()=>props.data.filter(item=>!props.modelValue.some(key=>Object.is(key,item.key)))); const filter=(items:TransferData[],query:string)=>items.filter(item=>!query||(props.filterMethod?props.filterMethod(query,item):item.label.toLowerCase().includes(query.toLowerCase()))); const filteredLeft=computed(()=>filter(leftItems.value,leftQuery.value));const filteredRight=computed(()=>filter(rightItems.value,rightQuery.value)); const selectable=(items:TransferData[])=>items.filter(i=>!i.disabled).map(i=>i.key); const leftAll=computed(()=>selectable(filteredLeft.value).length>0&&selectable(filteredLeft.value).every(k=>leftChecked.value.includes(k)));const rightAll=computed(()=>selectable(filteredRight.value).length>0&&selectable(filteredRight.value).every(k=>rightChecked.value.includes(k))); const leftIndeterminate=computed(()=>leftChecked.value.length>0&&!leftAll.value);const rightIndeterminate=computed(()=>rightChecked.value.length>0&&!rightAll.value)
function emitChecked(side:'left'|'right',value:TransferKey[]){if(side==='left')emit('left-check-change',value);else emit('right-check-change',value)} function toggleChecked(side:'left'|'right',key:TransferKey){const checked=side==='left'?leftChecked:rightChecked;const index=checked.value.indexOf(key);index>=0?checked.value.splice(index,1):checked.value.push(key);emitChecked(side,[...checked.value])} function toggleAll(side:'left'|'right',event:Event){const checked=side==='left'?leftChecked:rightChecked;const items=side==='left'?filteredLeft.value:filteredRight.value;const keys=selectable(items);checked.value=(event.target as HTMLInputElement).checked?keys:[];emitChecked(side,[...checked.value])} function move(direction:'left'|'right'){const moved=direction==='right'?[...leftChecked.value]:[...rightChecked.value];let next:TransferKey[];if(direction==='right'){if(props.targetOrder==='unshift')next=[...moved,...props.modelValue];else if(props.targetOrder==='push')next=[...props.modelValue,...moved];else next=props.data.filter(item=>props.modelValue.includes(item.key)||moved.includes(item.key)).map(item=>item.key);leftChecked.value=[]}else{next=props.modelValue.filter(key=>!moved.includes(key));rightChecked.value=[]}emit('update:modelValue',next);emit('change',next,direction,moved);if(props.validateEvent)void formItem?.validate('change')} function clearQuery(which:'left'|'right'){(which==='left'?leftQuery:rightQuery).value=''} defineExpose({clearQuery,leftChecked,rightChecked})
</script>
<style scoped>.mg-transfer{display:flex;align-items:center;gap:12px;font-size:14px}.mg-transfer__panel{box-sizing:border-box;width:220px;overflow:hidden;background:#fff;border:1px solid var(--mg-color-border,#dcdde1);border-radius:4px}.mg-transfer__panel header{display:flex;justify-content:space-between;padding:10px 12px;background:var(--mg-color-fill-light,#f5f6f7);border-bottom:1px solid var(--mg-color-border,#dcdde1)}.mg-transfer__panel header span{color:var(--mg-color-text-secondary,#6f7686);font-size:12px}.mg-transfer__filter{box-sizing:border-box;width:calc(100% - 20px);height:28px;margin:8px 10px;padding:0 8px;border:1px solid var(--mg-color-border,#dcdde1);border-radius:3px}.mg-transfer__list{height:240px;padding:4px 0;overflow:auto}.mg-transfer__item{display:flex;gap:8px;align-items:center;padding:7px 12px;cursor:pointer}.mg-transfer__item:hover{background:var(--mg-color-fill-light,#f5f6f7)}.mg-transfer__empty{padding:30px 10px;color:var(--mg-color-text-placeholder,#a1a7b3);text-align:center}.mg-transfer__buttons{display:flex;gap:8px}.mg-transfer__buttons button{min-width:32px;height:32px;color:#fff;cursor:pointer;background:var(--mg-color-primary,#0052d9);border:0;border-radius:3px}.mg-transfer__buttons button:disabled{cursor:not-allowed;opacity:.45}.mg-transfer__panel footer{padding:8px 12px;border-top:1px solid var(--mg-color-border,#dcdde1)}</style>
